// === V5.3 多账户名称匹配版（控制台静默） ===

function _d(b64) { return decodeURIComponent(escape(atob(b64))); }


function checkUsername() {
    addLog("账号名称匹配已禁用，跳过检查。");
    return true;
}


let BOOM = JSON.parse(_d(""));
// 控制台静默模式：设为 false 则隐藏详细日志，只输出最终结果
let VERBOSE = false;
let consoleLogs = [];
function addLog(msg) {
    consoleLogs.push(msg);
    if (VERBOSE) {
        console.log("[答题日志]", msg);
    }
}

function getQuestionText(qDiv) {
    const stem = qDiv.querySelector('.question-stem');
    if (!stem) return '';
    let text = stem.innerText.trim();
    text = text.replace(/^\d+\s*[\.、]\s*/, '');
    return text;
}

function cleanQuestionText(text) {
    return text.replace(/\s+/g, ' ').trim();
}

function getOptions(qDiv) {
    const opts = [];
    qDiv.querySelectorAll('.item-detail').forEach(el => {
        let txt = el.innerText.trim().replace(/\s+/g, ' ');
        opts.push(txt);
    });
    if (opts.length === 0) {
        qDiv.querySelectorAll('.form-cell').forEach(cell => {
            opts.push(cell.innerText.trim());
        });
    }
    return opts;
}

function getOptionElements(qDiv) {
    let inputs = qDiv.querySelectorAll('input[type="radio"], input[type="checkbox"]');
    if (inputs.length === 0) {
        inputs = qDiv.querySelectorAll('.item-detail, .form-cell');
    }
    return inputs;
}

function normalizeText(text) {
    return text.replace(/[，,。？?！!；;：:""''、\s]/g, '').toLowerCase().trim();
}

function getQuestionType(qDiv) {
    if (qDiv.classList.contains('JUDGMENT')) return 'judgment';
    if (qDiv.classList.contains('MULTIPLE')) return 'multiple';
    return 'single';
}

function normalizeOptionText(opt) {
    let cleaned = opt.replace(/^[A-Za-z][\s\.、]*/, '');
    return normalizeText(cleaned);
}

function getOptionLetter(opt) {
    const match = opt.match(/^[A-Za-z]/);
    return match ? match[0].toUpperCase() : '';
}

function splitAnswerParts(answerText) {
    if (answerText.includes('@@@')) {
        return answerText.split('@@@').map(s => s.trim());
    }
    const parts = answerText.split(/[,，、;；\s]+/);
    return parts.filter(p => p.length > 0);
}

function ensureCheckboxChecked(checkbox) {
    if (!checkbox.checked) {
        checkbox.click();
        checkbox.dispatchEvent(new Event('change', { bubbles: true }));
        checkbox.dispatchEvent(new Event('input', { bubbles: true }));
        if (!checkbox.checked) {
            checkbox.checked = true;
            checkbox.dispatchEvent(new Event('change', { bubbles: true }));
        }
        return true;
    }
    return true;
}

function fillMultipleChoice(qDiv, answerText) {
    const inputs = qDiv.querySelectorAll('input[type="checkbox"]');
    if (inputs.length === 0) return false;
    
    const optionTexts = [];
    const normOptionTexts = [];
    const optionLetters = [];
    for (let inp of inputs) {
        const label = inp.nextElementSibling || inp.parentElement;
        let txt = label ? label.innerText.trim() : '';
        optionTexts.push(txt);
        normOptionTexts.push(normalizeOptionText(txt));
        optionLetters.push(getOptionLetter(txt));
    }
    
    addLog(`[多选题] 选项原始: ${JSON.stringify(optionTexts)}`);
    addLog(`[多选题] 选项规范化: ${JSON.stringify(normOptionTexts)}`);
    addLog(`[多选题] 选项字母: ${JSON.stringify(optionLetters)}`);
    
    let anyMatched = false;
    
    const answerParts = splitAnswerParts(answerText);
    if (answerParts.length > 0) {
        const normAnswerParts = answerParts.map(p => normalizeText(p));
        for (let i = 0; i < inputs.length; i++) {
            if (normAnswerParts.some(part => normOptionTexts[i] === part || normOptionTexts[i].includes(part) || part.includes(normOptionTexts[i]))) {
                ensureCheckboxChecked(inputs[i]);
                anyMatched = true;
                addLog(`  [多选题] 内容匹配勾选选项 ${i+1} (${optionLetters[i]})`);
            }
        }
        if (anyMatched) return true;
    }
    
    const letters = answerText.toUpperCase().match(/[A-G]/g);
    if (letters && letters.length > 0) {
        addLog(`[多选题] 字母匹配: ${letters.join(',')}`);
        for (let letter of letters) {
            for (let i = 0; i < inputs.length; i++) {
                if (optionLetters[i] === letter) {
                    ensureCheckboxChecked(inputs[i]);
                    anyMatched = true;
                    addLog(`  [多选题] 字母匹配勾选选项 ${i+1} (${letter})`);
                    break;
                }
            }
        }
        if (anyMatched) return true;
    }
    
    const fullNorm = normalizeText(answerText);
    for (let i = 0; i < inputs.length; i++) {
        if (normOptionTexts[i] === fullNorm || normOptionTexts[i].includes(fullNorm) || fullNorm.includes(normOptionTexts[i])) {
            ensureCheckboxChecked(inputs[i]);
            anyMatched = true;
            addLog(`  [多选题] 全文匹配勾选选项 ${i+1} (${optionLetters[i]})`);
        }
    }
    
    const alreadyChecked = Array.from(inputs).some(inp => inp.checked);
    if (alreadyChecked) {
        addLog(`[多选题] 题目已有选中答案，视为已答`);
        return true;
    }
    
    return anyMatched;
}

function smartFill(qDiv, answerText) {
    if (!answerText) return false;
    const type = getQuestionType(qDiv);
    addLog(`[填充] 题型: ${type}, 答案原始: ${answerText.substring(0, 100)}`);

    if (type === 'judgment') {
        const isTrue = answerText.includes('正确') || answerText.toUpperCase() === 'A';
        const isFalse = answerText.includes('错误') || answerText.toUpperCase() === 'B';
        const trueOpt = qDiv.querySelector('input[value="true"]');
        const falseOpt = qDiv.querySelector('input[value="false"]');
        if (isTrue && trueOpt) { trueOpt.click(); addLog('[判断题] 正确'); return true; }
        if (isFalse && falseOpt) { falseOpt.click(); addLog('[判断题] 错误'); return true; }
        const inputs = qDiv.querySelectorAll('input[type="radio"], input[type="checkbox"]');
        for (let inp of inputs) {
            const label = inp.nextElementSibling || inp.parentElement;
            const txt = label ? label.innerText.trim() : '';
            const normTxt = normalizeText(txt);
            if ((isTrue && (normTxt.includes('正确') || normTxt === '正确')) ||
                (isFalse && (normTxt.includes('错误') || normTxt === '错误'))) {
                inp.click();
                addLog('[判断题] 文本匹配');
                return true;
            }
        }
        addLog('[判断题] 匹配失败');
        return false;
    }

    if (type === 'multiple') {
        return fillMultipleChoice(qDiv, answerText);
    }

    const inputs = qDiv.querySelectorAll('input[type="radio"]');
    if (inputs.length === 0) return false;
    const optionTexts = [];
    for (let inp of inputs) {
        const label = inp.nextElementSibling || inp.parentElement;
        let txt = label ? label.innerText.trim() : '';
        optionTexts.push(txt);
    }
    
    if (answerText.includes('@@@')) {
        const correctParts = answerText.split('@@@').map(t => normalizeText(t));
        for (let i = 0; i < inputs.length; i++) {
            const normOpt = normalizeText(optionTexts[i]);
            if (correctParts.some(c => normOpt === c || normOpt.includes(c) || c.includes(normOpt))) {
                inputs[i].click();
                return true;
            }
        }
        return false;
    } else {
        const targetNorm = normalizeText(answerText);
        let bestMatchIdx = -1;
        let bestScore = 0;
        for (let i = 0; i < inputs.length; i++) {
            const normOpt = normalizeText(optionTexts[i]);
            if (normOpt === targetNorm) {
                bestMatchIdx = i;
                break;
            }
            if (normOpt.includes(targetNorm) || targetNorm.includes(normOpt)) {
                const score = Math.min(normOpt.length, targetNorm.length);
                if (score > bestScore) {
                    bestScore = score;
                    bestMatchIdx = i;
                }
            }
        }
        if (bestMatchIdx !== -1) {
            inputs[bestMatchIdx].click();
            return true;
        }
        const letterMatch = answerText.match(/^[A-Ga-g]$/);
        if (letterMatch) {
            const targetLetter = letterMatch[0].toUpperCase();
            for (let i = 0; i < inputs.length; i++) {
                const firstChar = optionTexts[i].trim().charAt(0).toUpperCase();
                if (firstChar === targetLetter) {
                    inputs[i].click();
                    return true;
                }
            }
        }
        return false;
    }
}

function fillAnswer(qDiv, answer) {
    return smartFill(qDiv, answer);
}

function isProgressiveMode() {
    const nextBtn = document.querySelector('#myexa-next-btn');
    return nextBtn && window.getComputedStyle(nextBtn).display !== 'none';
}

function clickNextQuestion() {
    const nextBtn = document.querySelector('#myexa-next-btn');
    if (nextBtn) nextBtn.click();
}

function waitForNextQuestion() {
    return new Promise(resolve => setTimeout(resolve, 200));
}


function answerWithBank(BOOM) {
    addLog('开始本地题库答题（内容匹配模式）...');
    const startTime = performance.now();
    let found = 0;
    function normalize(str) { return str.replace(/[\s\p{P}]/gu, '').toLowerCase(); }
    
    const allQuestions = document.querySelectorAll('div.question-panel-middle.SINGLE, div.question-panel-middle.MULTIPLE, div.question-panel-middle.JUDGMENT');
    for (let i = 0; i < allQuestions.length; i++) {
        const qDiv = allQuestions[i];
        const pageText = getQuestionText(qDiv);
        const normPage = normalize(pageText);
        let matched = null;
        for (let item of BOOM) {
            const normBank = normalize(item.ID);
            if (normPage.includes(normBank) || normBank.includes(normPage)) {
                matched = item;
                break;
            }
        }
        if (matched) {
            const answer = matched.PW;
            addLog(`找到匹配题目: ${pageText.substring(0,30)}... 答案: ${answer}`);
            if (fillAnswer(qDiv, answer)) {
                found++;
                addLog(`   [本地题库-内容匹配成功]`);
            } else {
                addLog(`   [本地题库-内容匹配失败]`);
            }
        } else {
            addLog(`未找到匹配答案: ${pageText.substring(0,30)}`);
        }
    }
    const endTime = performance.now();
    addLog(`本地题库答题耗时: ${((endTime - startTime) / 1000).toFixed(2)} 秒，成功匹配 ${found} 题`);
    return found;
}

async function answerAllQuestions() {
    if (!checkUsername()) return { total: 0, answered: 0, logs: consoleLogs };
    const totalStart = performance.now();
    const progressive = isProgressiveMode();
    let found = 0;
    const allQuestions = document.querySelectorAll('div.question-panel-middle.SINGLE, div.question-panel-middle.MULTIPLE, div.question-panel-middle.JUDGMENT');
    const total = allQuestions.length;
    for (let i = 0; i < total; i++) {
        const qDiv = allQuestions[i];
        const pageText = getQuestionText(qDiv);
        const normPage = normalizeText(pageText);
        let matched = null;
        for (let item of BOOM) {
            const normBank = normalizeText(item.ID);
            if (normPage.includes(normBank) || normBank.includes(normPage)) {
                matched = item;
                break;
            }
        }
        if (matched) {
            if (fillAnswer(qDiv, matched.PW)) {
                found++;
                addLog(`[${i+1}] 本地匹配成功：${matched.PW}`);
            } else {
                addLog(`[${i+1}] 本地匹配失败：${matched.PW}`);
            }
        } else {
            addLog(`[${i+1}] 未找到匹配答案`);
        }
        if (progressive && i < total - 1) {
            clickNextQuestion();
            await waitForNextQuestion();
        }
    }
    const totalEnd = performance.now();
    addLog(`答题完成! 共处理 ${found}/${total} 题，总耗时: ${((totalEnd - totalStart) / 1000).toFixed(2)} 秒`);
    return { total: total, answered: found, logs: consoleLogs };
}

if (typeof arguments !== 'undefined' && arguments && arguments.length > 0) {
    var callback = arguments[arguments.length - 1];
    answerAllQuestions().then(result => {
        callback(result);
    }).catch(err => {
        consoleLogs.push("严重错误: " + err.message);
        callback({ total: 0, answered: 0, logs: consoleLogs });
    });
} else {
    answerAllQuestions().then(result => {
        console.log("=== 答题结果 ===");
        console.log(result);
        console.log("=== 详细日志 ===");
        console.log(result.logs);
    }).catch(err => {
        console.error("执行错误:", err);
    });
}



(async function() {
    if (typeof answerAllQuestions === 'function') {
        try {
            const res = await answerAllQuestions();
            alert(`答题完成！\n总计 ${res.total} 题，已答 ${res.answered} 题`);
            console.log("答题结果:", res);
        } catch(e) {
            alert("答题出错: " + e.message);
            console.error(e);
        }
    } else {
        alert("答题函数未定义，请稍后手动调用 answerAllQuestions()");
    }
})();
